mapper.select:
select cp.char_id , cp.appearance , cp.art_style , cp.negative , cp.personality_traits , cp.url_img 
from character_prompt cp 
where cp.char_id =  #{id}

select cp.sub_id , cp.sub_title, cp.sub_appearance , cp.sub_anti_yn , cp.sub_negative , cp.sub_url_img 
from sub_character  cp 
where cp.sub_id =  #{id}
